		MultiRepoSailDataset dataset = new MultiRepoSailDataset(List.of(
				new OrderedDataset(Comparator.comparing(Value::stringValue)),
				new OrderedDataset(Comparator.comparing(Value::stringValue).reversed())));

		assertThat(dataset.getSupportedOrders(null, null, null)).isEmpty();
		assertThat(dataset.getComparator()).isNull();
