	private Repository createMultiRepoRepository(File dataDir, RepositoryResolver resolver,
			MultiRepoStoreConfig config) {
		SailRepository repository = new SailRepository(new MultiRepoStore(config));
		repository.setDataDir(dataDir);
		if (resolver != null) {
			repository.setRepositoryResolver(resolver);
		}
		repository.init();
		return repository;
	}

	private void addMemoryStore(LocalRepositoryManager manager, String repositoryId) {
		RepositoryImplConfig implConfig = new SailRepositoryConfig(new MemoryStoreConfig());
		RepositoryConfig config = new RepositoryConfig(repositoryId, implConfig);
		manager.addRepositoryConfig(config);
	}

	private void add(LocalRepositoryManager manager, String repositoryId, IRI subject, IRI predicate, IRI object,
			Resource... contexts) {
		add(manager.getRepository(repositoryId), subject, predicate, object, contexts);
	}

	private void add(Repository repository, IRI subject, IRI predicate, IRI object, Resource... contexts) {
		try (RepositoryConnection connection = repository.getConnection()) {
			connection.add(subject, predicate, object, contexts);
		}
	}

	private void addInferred(Repository repository, IRI subject, IRI predicate, IRI object, Resource... contexts)
			throws SailException {
		Sail sail = ((SailRepository) repository).getSail();
		try (InferencerConnection connection = (InferencerConnection) sail.getConnection()) {
			connection.begin();
			connection.addInferredStatement(subject, predicate, object, contexts);
			connection.commit();
		}
	}

	private void writeStore(Sail sail, IRI subject, IRI predicate, IRI object) {
		Repository repository = new SailRepository(sail);
		try {
			repository.init();
			add(repository, subject, predicate, object);
		} finally {
			repository.shutDown();
		}
	}

	private static final class NarrowIsolationMemoryStore extends MemoryStore {

		private NarrowIsolationMemoryStore(IsolationLevel... isolationLevels) {
			setSupportedIsolationLevels(isolationLevels);
			setDefaultIsolationLevel(isolationLevels[0]);
		}
	}

